import { Component, inject, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { AdminCasesService } from '../../../application/services/admin-cases.service';
import { CaseItem, PagedResponse } from '../../../application/models/backoffice.models';

@Component({
  selector: 'bo-case-list',
  templateUrl: './case-list.component.html',
  styleUrls: ['./case-list.component.css']
})
export class CaseListComponent implements OnInit {
  private readonly adminCasesService = inject(AdminCasesService);
  private readonly router = inject(Router);

  Math = Math;

  cases: CaseItem[] = [];
  isLoading = true;
  currentPage = 0;
  pageSize = 10;
  totalItems = 0;
  totalPages = 0;
  statusFilter = '';

  statusOptions = [
    { value: '', label: 'Todos' },
    { value: 'DRAFT', label: 'Borrador' },
    { value: 'SUBMITTED', label: 'Presentado' },
    { value: 'IN_PROGRESS', label: 'En Tramitacion' },
    { value: 'PENDING_AMENDMENT', label: 'Pendiente Subsanacion' },
    { value: 'RESOLVED', label: 'Resuelto' },
    { value: 'REJECTED', label: 'Rechazado' }
  ];

  ngOnInit(): void {
    this.loadCases();
  }

  loadCases(): void {
    this.isLoading = true;
    this.adminCasesService.list(this.currentPage, this.pageSize, undefined, this.statusFilter || undefined).subscribe({
      next: (response: PagedResponse<CaseItem>) => {
        this.cases = response.items;
        this.totalItems = response.totalItems;
        this.totalPages = response.totalPages;
        this.isLoading = false;
      },
      error: () => {
        this.cases = [];
        this.isLoading = false;
      }
    });
  }

  onStatusChange(status: string): void {
    this.statusFilter = status;
    this.currentPage = 0;
    this.loadCases();
  }

  onPageChange(page: number): void {
    this.currentPage = page;
    this.loadCases();
  }

  viewCase(id: string): void {
    this.router.navigate(['/cases', id]);
  }

  getStatusLabel(status: string): string {
    const option = this.statusOptions.find(o => o.value === status);
    return option?.label || status;
  }

  getStatusClass(status: string): string {
    const classes: Record<string, string> = {
      DRAFT: 'bg-gray-100 text-gray-800',
      SUBMITTED: 'bg-blue-100 text-blue-800',
      IN_PROGRESS: 'bg-yellow-100 text-yellow-800',
      PENDING_AMENDMENT: 'bg-orange-100 text-orange-800',
      RESOLVED: 'bg-green-100 text-green-800',
      REJECTED: 'bg-red-100 text-red-800'
    };
    return classes[status] || 'bg-gray-100 text-gray-800';
  }
}
<div class="bg-white rounded-lg shadow">
  <!-- Filters -->
  <div class="px-6 py-4 border-b border-gray-200">
    <div class="flex items-center justify-between">
      <h3 class="text-lg font-semibold text-gray-900">Expedientes</h3>
      <div class="flex items-center gap-4">
        <label for="statusFilter" class="text-sm text-gray-600">Estado:</label>
        <select
          id="statusFilter"
          [value]="statusFilter"
          (change)="onStatusChange($any($event.target).value)"
          class="border border-gray-300 rounded-md px-3 py-1.5 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
        >
          <option *ngFor="let opt of statusOptions" [value]="opt.value">{{ opt.label }}</option>
        </select>
      </div>
    </div>
  </div>

  <!-- Loading state -->
  <div *ngIf="isLoading" class="flex items-center justify-center h-64">
    <div class="text-gray-500">Cargando expedientes...</div>
  </div>

  <!-- Cases table -->
  <div *ngIf="!isLoading" class="overflow-x-auto">
    <table class="w-full">
      <thead class="bg-gray-50 border-b border-gray-200">
        <tr>
          <th class="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Expediente</th>
          <th class="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Tipo</th>
          <th class="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Ciudadano</th>
          <th class="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Estado</th>
          <th class="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Tarea Actual</th>
          <th class="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Ultima Actualizacion</th>
          <th class="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Acciones</th>
        </tr>
      </thead>
      <tbody class="divide-y divide-gray-200">
        <tr *ngFor="let caseItem of cases" class="hover:bg-gray-50">
          <td class="px-6 py-4">
            <div class="font-medium text-gray-900">{{ caseItem.title }}</div>
            <div class="text-sm text-gray-500 truncate max-w-xs">{{ caseItem.id }}</div>
          </td>
          <td class="px-6 py-4 text-sm text-gray-600">{{ caseItem.procedureType }}</td>
          <td class="px-6 py-4 text-sm text-gray-600">{{ caseItem.citizenName }}</td>
          <td class="px-6 py-4">
            <span class="px-2 py-1 text-xs font-medium rounded-full" [ngClass]="getStatusClass(caseItem.status)">
              {{ getStatusLabel(caseItem.status) }}
            </span>
          </td>
          <td class="px-6 py-4 text-sm text-gray-600">{{ caseItem.currentTask || '-' }}</td>
          <td class="px-6 py-4 text-sm text-gray-500">{{ caseItem.lastUpdated | date: 'dd/MM/yyyy HH:mm' }}</td>
          <td class="px-6 py-4 text-right">
            <button
              (click)="viewCase(caseItem.id)"
              class="text-blue-600 hover:text-blue-800 text-sm font-medium"
            >
              Ver detalle
            </button>
          </td>
        </tr>
        <tr *ngIf="cases.length === 0">
          <td colspan="7" class="px-6 py-8 text-center text-gray-500">
            No se encontraron expedientes
          </td>
        </tr>
      </tbody>
    </table>
  </div>

  <!-- Pagination -->
  <div *ngIf="!isLoading && totalPages > 1" class="px-6 py-4 border-t border-gray-200 flex items-center justify-between">
    <div class="text-sm text-gray-500">
      Mostrando {{ currentPage * pageSize + 1 }} - {{ Math.min((currentPage + 1) * pageSize, totalItems) }} de {{ totalItems }}
    </div>
    <div class="flex gap-2">
      <button
        [disabled]="currentPage === 0"
        (click)="onPageChange(currentPage - 1)"
        class="px-3 py-1 border border-gray-300 rounded text-sm disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-50"
      >
        Anterior
      </button>
      <button
        [disabled]="currentPage >= totalPages - 1"
        (click)="onPageChange(currentPage + 1)"
        class="px-3 py-1 border border-gray-300 rounded text-sm disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-50"
      >
        Siguiente
      </button>
    </div>
  </div>
</div>
